import os
import hashlib
from flask import Flask, request, jsonify, abort
from prometheus_client import Counter, Histogram, Gauge, generate_latest, CONTENT_TYPE_LATEST
from functools import wraps
import time
import secrets

app = Flask(__name__)

METRICS_TOKEN = os.environ.get('METRICS_TOKEN', secrets.token_urlsafe(32))

request_count = Counter(
    'api_requests_total',
    'Total API requests',
    ['method', 'endpoint', 'status']
)

request_duration = Histogram(
    'api_request_duration_seconds',
    'API request duration',
    ['method', 'endpoint']
)

active_requests = Gauge(
    'api_active_requests',
    'Number of active requests'
)

user_requests = Counter(
    'api_user_requests_total',
    'Total requests per user',
    ['user_hash']
)

endpoint_requests = Counter(
    'api_endpoint_requests_total',
    'Total requests per endpoint',
    ['endpoint', 'method']
)


def hash_sensitive_data(data):
    if not data:
        return 'anonymous'
    return hashlib.sha256(str(data).encode()).hexdigest()[:16]


def require_metrics_token(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get('X-Metrics-Token')
        if not token or not secrets.compare_digest(token, METRICS_TOKEN):
            abort(403)
        return f(*args, **kwargs)
    return decorated_function


@app.before_request
def before_request():
    request.start_time = time.time()
    active_requests.inc()


@app.after_request
def after_request(response):
    active_requests.dec()
    
    if request.endpoint and request.endpoint != 'metrics':
        duration = time.time() - request.start_time
        
        request_count.labels(
            method=request.method,
            endpoint=request.endpoint,
            status=response.status_code
        ).inc()
        
        request_duration.labels(
            method=request.method,
            endpoint=request.endpoint
        ).observe(duration)
        
        endpoint_requests.labels(
            endpoint=request.endpoint,
            method=request.method
        ).inc()
        
        user_id = request.headers.get('X-User-ID') or request.args.get('user_id')
        if user_id:
            user_hash = hash_sensitive_data(user_id)
            user_requests.labels(user_hash=user_hash).inc()
    
    return response


@app.route('/metrics')
@require_metrics_token
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}


@app.route('/api/data', methods=['GET', 'POST'])
def api_data():
    return jsonify({'status': 'success', 'data': 'sample data'})


@app.route('/api/users/<user_id>', methods=['GET'])
def get_user(user_id):
    return jsonify({'user_id': user_id, 'name': 'Sample User'})


@app.route('/health')
def health():
    return jsonify({'status': 'healthy'})


if __name__ == '__main__':
    print(f"Metrics token: {METRICS_TOKEN}")
    print("Use header: X-Metrics-Token: <token> to access /metrics")
    app.run(host='127.0.0.1', port=5000, debug=False)